command:
// =========================
// MASTER DUNGEON GENERATOR
// Overview + Levels + Room Details
// =========================

function roll(sides) {
    return Math.ceil(Math.random() * sides);
}

function pick(table) {
    const r = roll(table.length);
    return { roll: r, result: table[r - 1] };
}

function tableRoll(value, table) {
    return table.find(row => value >= row.min && value <= row.max);
}

// ---------- OVERVIEW TABLES ----------

const dungeonTypes = [
    "Ancient Tomb", "Abandoned Mine", "Natural Cave", "Bandit Hideout",
"Goblin Warrens", "Lost Temple", "Wizard Laboratory", "Forgotten Fortress",
"Underground City", "Crypt", "Sewers", "Ancient Ruins"
];

const dungeonThemes = [
    "Decay", "Death", "Fire", "Ice", "Nature", "Corruption",
"Madness", "Undead", "Demons", "Lost Civilization",
"Forbidden Knowledge", "Monsters"
];

const dungeonPurposes = [
    "Burial site", "Military outpost", "Religious center", "Prison",
"Research facility", "Treasure vault", "Refuge", "Monster lair",
"Ancient city", "Trade route", "Secret meeting place", "Portal nexus"
];

const crossSections = [
    "Single Level", "Single Level", "Single Level", "Single Level",
"Two Levels", "Two Levels", "Three Levels", "Three Levels",
"Four Levels", "Five Levels", "Six Levels", "Mega Dungeon"
];

const roomDensity = [
    { name: "Small", formula: "1d6 + 4" },
{ name: "Medium", formula: "2d6 + 6" },
{ name: "Large", formula: "3d6 + 9" }
];

// ---------- ROOM TABLES ----------

const roomPurposeTable = [
    { name: "Combat", description: "Danger, enemies, ambushes, guards, monsters, or hostile creatures." },
{ name: "Cache", description: "Treasure, supplies, equipment, clues, or useful rewards." },
{ name: "Sidekick", description: "An ally, prisoner, guide, rescued NPC, or helpful creature." },
{ name: "Offshoot", description: "Optional side path, hidden area, shortcut, or risky detour." },
{ name: "Foreshadowing", description: "A clue, omen, warning, remains, tracks, or signs of future danger." },
{ name: "History", description: "Lore about the dungeon, its builders, former inhabitants, disaster, religion, or purpose." },
{ name: "Oddity", description: "A strange, memorable, magical, creepy, or unexplained feature." },
{ name: "Forge", description: "Crafting, repair, upgrades, enchanting, restoring, or modifying gear." },
{ name: "Factions", description: "Social or political scene involving rival groups, scouts, negotiations, or disputes." },
{ name: "Map", description: "Directions, secret passages, nearby rooms, future locations, or world clues." },
{ name: "Puzzle", description: "An obstacle requiring observation, interaction, experimentation, or problem-solving." }
];

const detailTables = {
    Combat: {
        main: ["Guard post", "Ambush", "Wandering monster", "Boss/miniboss", "Territorial beasts", "Rival explorers"],
        twist: ["Poor lighting", "Difficult terrain", "Hazard nearby", "Enemies distracted", "Reinforcements possible", "Enemy morale is shaky"]
    },
    Cache: {
        main: ["Coins/valuables", "Useful supplies", "Weapons/armor", "Map/clue", "Trade goods", "Potion/consumable"],
        twist: ["Hidden", "Locked", "Trapped", "Guarded", "Damaged", "Clearly stolen"]
    },
    Sidekick: {
        main: ["Prisoner", "Lost adventurer", "Wounded scout", "Local guide", "Strange creature", "Defector"],
        twist: ["Afraid", "Injured", "Knows a secret", "Being hunted", "Not fully honest", "Has useful skills"]
    },
    Offshoot: {
        main: ["Hidden side room", "Collapsed passage", "Shortcut", "Vertical shaft", "Secret tunnel", "Optional danger room"],
        twist: ["Hard to notice", "Requires tools", "One-way path", "Partially flooded", "Unstable", "Leads near a major threat"]
    },
    Foreshadowing: {
        main: ["Claw marks", "Old warning", "Corpse", "Strange symbol", "Distant sound", "Abandoned gear"],
        twist: ["Points to boss", "Warns of trap", "Hints at faction", "Reveals monster weakness", "Shows past disaster", "Misleading clue"]
    },
    History: {
        main: ["Mural", "Inscription", "Old journal", "Statue", "Tomb carving", "Broken relic"],
        twist: ["Names the builders", "Explains the dungeon purpose", "Shows betrayal", "Mentions a lost treasure", "Warns of a curse", "Connects to a faction"]
    },
    Oddity: {
        main: [
            "Whispering wall", "Floating object", "Impossible shadow", "Room colder than it should be",
            "Living stone", "Repeating vision", "Ancient shrine", "Portal room",
            "Collapsed wonder", "Ritual chamber", "Secret garden", "Artifact display"
        ],
        twist: [
            "Harmless but strange", "Minor magical effect", "Useful clue", "Tempts interaction",
            "Changes when observed", "Attracts monsters", "Magically protected",
            "Recently disturbed", "Haunted", "Still active", "Partially destroyed", "Hidden"
        ]
    },
    Forge: {
        main: ["Blacksmith forge", "Alchemy bench", "Enchanting circle", "Repair station", "Ancient machine", "Crafting supplies"],
        twist: ["Still usable", "Needs fuel", "Requires rare component", "Dangerous malfunction", "Can upgrade gear", "Someone already uses it"]
    },
    Factions: {
        main: ["Faction guards", "Negotiation scene", "Prisoner exchange", "Faction shrine", "Spy meeting", "Internal argument"],
        twist: ["Can be bargained with", "Hostile on sight", "Rival faction nearby", "One member defects", "They want help", "They are hiding something"]
    },
    Map: {
        main: ["Dungeon map", "Regional map", "Secret passage clue", "Treasure route", "Faction territory map", "Warning diagram"],
        twist: ["Incomplete", "Outdated", "Encoded", "Trapped", "Shows hidden entrance", "Points to another hex"]
    },
    Puzzle: {
        main: ["Lever puzzle", "Riddle door", "Pressure plates", "Symbol sequence", "Rotating room", "Light/mirror puzzle"],
        twist: ["Failure causes damage", "Failure summons enemy", "Timed challenge", "Multiple solutions", "Clue nearby", "Bypass possible at a cost"]
    }
};

const conditionTable = [
    "Pristine / untouched", "Dusty but usable", "Damaged",
"Partially collapsed", "Recently disturbed", "Actively in use"
];

const sensoryTable = [
    "Cold air", "Damp smell", "Old blood", "Burnt scent", "Whispers or echoes",
"Scratching sounds", "Faint light", "Rotten smell", "Heavy silence", "Strange vibration"
];

// ---------- OPTIONS ----------

const maxRooms = await Dialog.prompt({
    title: "Master Dungeon Generator",
    content: `
    <p>Safety limit: maximum total rooms?</p>
    <input id="maxRooms" type="number" value="40" min="5" max="200"/>
    <p><i>This prevents mega dungeons from flooding chat.</i></p>
    `,
    callback: html => Number(html.find("#maxRooms").val())
});

// ---------- OVERVIEW ROLLS ----------

const type = pick(dungeonTypes);
const theme = pick(dungeonThemes);
const purpose = pick(dungeonPurposes);
const cross = pick(crossSections);
const size = pick(roomDensity);

let levels = 1;

if (cross.result === "Two Levels") levels = 2;
else if (cross.result === "Three Levels") levels = 3;
else if (cross.result === "Four Levels") levels = 4;
else if (cross.result === "Five Levels") levels = 5;
else if (cross.result === "Six Levels") levels = 6;
else if (cross.result === "Mega Dungeon") levels = roll(6) + 6;

const dangerRoll = roll(6);
const danger = [
    "Mostly abandoned",
"Minor threats",
"Moderate danger",
"Hostile dungeon",
"Extremely dangerous",
"Deadly"
][dangerRoll - 1];

// ---------- ROOM COUNT ----------

function rollRoomCount(sizeName) {
    if (sizeName === "Small") {
        const r = roll(6);
        return { rooms: r + 4, rollText: `1d6 + 4 = ${r} + 4` };
    }

    if (sizeName === "Medium") {
        const r1 = roll(6);
        const r2 = roll(6);
        return { rooms: r1 + r2 + 6, rollText: `2d6 + 6 = ${r1} + ${r2} + 6` };
    }

    const r1 = roll(6);
    const r2 = roll(6);
    const r3 = roll(6);
    return { rooms: r1 + r2 + r3 + 9, rollText: `3d6 + 9 = ${r1} + ${r2} + ${r3} + 9` };
}

let dungeonLevels = [];
let totalRooms = 0;

for (let level = 1; level <= levels; level++) {
    const roomData = rollRoomCount(size.result.name);

    if (totalRooms + roomData.rooms > maxRooms) {
        roomData.rooms = Math.max(0, maxRooms - totalRooms);
    }

    totalRooms += roomData.rooms;

    dungeonLevels.push({
        level,
        roomRollText: roomData.rollText,
        roomCount: roomData.rooms,
        rooms: []
    });

    if (totalRooms >= maxRooms) break;
}

// ---------- GENERATE ROOMS ----------

for (const level of dungeonLevels) {
    let previousPurpose = null;

    for (let i = 1; i <= level.roomCount; i++) {
        let purposeRoll;
        let purposeData;
        let attempts = 0;

        do {
            purposeRoll = roll(11);
            purposeData = roomPurposeTable[purposeRoll - 1];
            attempts++;
        } while (
            previousPurpose &&
            purposeData.name === previousPurpose &&
            purposeData.name !== "Combat" &&
            purposeData.name !== "Oddity" &&
            attempts < 20
        );

        const main = pick(detailTables[purposeData.name].main);
        const twist = pick(detailTables[purposeData.name].twist);
        const condition = pick(conditionTable);
        const sensory = pick(sensoryTable);

        level.rooms.push({
            number: i,
            purposeRoll,
            purpose: purposeData.name,
            description: purposeData.description,
            main,
            twist,
            condition,
            sensory
        });

        previousPurpose = purposeData.name;
    }
}

// ---------- OUTPUT ----------

let output = `
<h2>Master Dungeon Generator</h2>

<h3>Overview</h3>

<p><b>Dungeon Type Roll:</b> d12 = ${type.roll}</p>
<p><b>Dungeon Type:</b> ${type.result}</p>

<p><b>Theme Roll:</b> d12 = ${theme.roll}</p>
<p><b>Theme:</b> ${theme.result}</p>

<p><b>Purpose Roll:</b> d12 = ${purpose.roll}</p>
<p><b>Purpose:</b> ${purpose.result}</p>

<p><b>Cross-Section Roll:</b> d12 = ${cross.roll}</p>
<p><b>Cross-Section:</b> ${cross.result}</p>

<p><b>Dungeon Size Roll:</b> d3 = ${size.roll}</p>
<p><b>Dungeon Size:</b> ${size.result.name} (${size.result.formula} rooms per level)</p>

<p><b>Danger Roll:</b> d6 = ${dangerRoll}</p>
<p><b>Danger:</b> ${danger}</p>

<p><b>Generated Levels:</b> ${dungeonLevels.length}</p>
<p><b>Total Rooms:</b> ${totalRooms}</p>

<hr>

<h3>Quick Dungeon Summary</h3>
<p>
This dungeon is a <b>${type.result.toLowerCase()}</b> built as a
<b>${purpose.result.toLowerCase()}</b>. Its theme is
<b>${theme.result.toLowerCase()}</b>. It has <b>${dungeonLevels.length}</b> level${dungeonLevels.length === 1 ? "" : "s"}
and <b>${totalRooms}</b> generated room${totalRooms === 1 ? "" : "s"}.
Overall danger: <b>${danger}</b>.
</p>

<hr>
`;

for (const level of dungeonLevels) {
    output += `
    <h3>Level ${level.level}</h3>
    <p><b>Room Count Roll:</b> ${level.roomRollText}</p>
    <p><b>Rooms on Level:</b> ${level.roomCount}</p>

    <ol>
    ${level.rooms.map(room => `
        <li>
        <h4>Room ${level.level}.${room.number}: ${room.purpose}</h4>

        <p><b>Purpose Roll:</b> d11 = ${room.purposeRoll}</p>
        <p><i>${room.description}</i></p>

        <p><b>${room.purpose} Detail Roll:</b> d${detailTables[room.purpose].main.length} = ${room.main.roll}</p>
        <p><b>Main Detail:</b> ${room.main.result}</p>

        <p><b>Twist Roll:</b> d${detailTables[room.purpose].twist.length} = ${room.twist.roll}</p>
        <p><b>Twist:</b> ${room.twist.result}</p>

        <p><b>Condition Roll:</b> d6 = ${room.condition.roll}</p>
        <p><b>Condition:</b> ${room.condition.result}</p>

        <p><b>Sensory Roll:</b> d10 = ${room.sensory.roll}</p>
        <p><b>Sensory:</b> ${room.sensory.result}</p>

        <p><b>Room Summary:</b> ${room.main.result}; ${room.twist.result}; ${room.condition.result}; ${room.sensory.result}.</p>
        </li>
        <br>
        `).join("")}
        </ol>

        <h4>Level ${level.level} Quick Summary</h4>
        <ul>
        ${level.rooms.map(room => `
            <li><b>${level.level}.${room.number}</b> — ${room.purpose}: ${room.main.result}; ${room.twist.result}</li>
            `).join("")}
            </ul>

            <hr>
            `;
}

ChatMessage.create({
    speaker: ChatMessage.getSpeaker(),
                   content: output
});
